export const PRODUCTS: Product[] = RAW_PRODUCTS.map(product => {
  const correctCategory = SUBCATEGORY_TO_CATEGORY[product.subcategory];
  if (correctCategory) {
    return { ...product, category: correctCategory };
  }
  return product;
});
